INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (0, 0, 2, 0, 1, "", 548, 60004, "", "今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (0, 0, 2, 0, 1, "", 549, 60004, "", "今日の運勢は姫吉！　宴でも開きたくなるほどの絶対幸運！\nイメチェンでもしてみるのはどうだ？　ぴょんぴょん、なんてな♪", 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (0, 0, 2, 0, 1, "", 550, 60004, "", "今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", 0, 1);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (0, 0, 2, 0, 1, "", 551, 60004, "", "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 0, 1);
